def _batched(iterable: cabc.Iterable[V], size: int) -> cabc.Iterator[tuple[V, ...]]:
    """Split ``iterable`` into tuples of at most ``size`` items each.
    Unlike :func:`batch`, the final chunk is yielded even if it is
    shorter than ``size``, so no items are dropped.
    """
    it = iter(iterable)

    while chunk := tuple(islice(it, size)):
        yield chunk

